package pl.msurvival.auth;import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.configuration.file.*;import org.bukkit.entity.*;import org.bukkit.event.*;import org.bukkit.event.block.*;import org.bukkit.event.player.*;import org.bukkit.plugin.java.JavaPlugin;import java.io.*;import java.security.*;import java.util.*;public final class MSurvivalAuth extends JavaPlugin implements Listener{private File f;private YamlConfiguration data;private final Set<UUID> logged=new HashSet<>();public void onEnable(){saveDefaultConfig();f=new File(getDataFolder(),"auth.yml");if(!f.exists())try{getDataFolder().mkdirs();f.createNewFile();}catch(Exception e){e.printStackTrace();}data=YamlConfiguration.loadConfiguration(f);Bukkit.getPluginManager().registerEvents(this,this);}public boolean onCommand(CommandSender s,Command c,String l,String[] a){if(c.getName().equalsIgnoreCase("authbypass")){if(!s.hasPermission("msurvival.auth.admin"))return true;List<String> list=new ArrayList<>(getConfig().getStringList("settings.bypass"));if(a.length>=2&&a[0].equalsIgnoreCase("add"))list.add(a[1]);if(a.length>=2&&a[0].equalsIgnoreCase("remove"))list.removeIf(x->x.equalsIgnoreCase(a[1]));getConfig().set("settings.bypass",list);saveConfig();s.sendMessage(list.toString());return true;}if(!(s instanceof Player p))return true;if(c.getName().equalsIgnoreCase("register")){if(bypass(p))return true;if(a.length<1){p.sendMessage(msg("register"));return true;}data.set("players."+p.getUniqueId()+".password",hash(a[0]));logged.add(p.getUniqueId());save();p.sendMessage(msg("ok"));return true;}if(c.getName().equalsIgnoreCase("login")){if(bypass(p))return true;if(a.length<1){p.sendMessage(msg("login"));return true;}if(hash(a[0]).equals(data.getString("players."+p.getUniqueId()+".password",""))){logged.add(p.getUniqueId());p.sendMessage(msg("ok"));}else p.sendMessage(msg("wrong"));return true;}return true;}@EventHandler public void join(PlayerJoinEvent e){Player p=e.getPlayer();if(bypass(p)){logged.add(p.getUniqueId());return;}Bukkit.getScheduler().runTaskLater(this,()->{if(!data.contains("players."+p.getUniqueId()+".password"))p.sendMessage(msg("register"));else p.sendMessage(msg("login"));},20L);Bukkit.getScheduler().runTaskLater(this,()->{if(p.isOnline()&&locked(p))p.kickPlayer(color(getConfig().getString("messages.timeout")));},getConfig().getLong("settings.login-timeout-seconds",60)*20L);}@EventHandler public void quit(PlayerQuitEvent e){logged.remove(e.getPlayer().getUniqueId());}@EventHandler public void move(PlayerMoveEvent e){if(locked(e.getPlayer()))e.setCancelled(true);}@EventHandler public void chat(AsyncPlayerChatEvent e){if(locked(e.getPlayer()))e.setCancelled(true);}@EventHandler public void cmd(PlayerCommandPreprocessEvent e){String m=e.getMessage().toLowerCase();if(locked(e.getPlayer())&&!m.startsWith("/login")&&!m.startsWith("/register"))e.setCancelled(true);}@EventHandler public void br(BlockBreakEvent e){if(locked(e.getPlayer()))e.setCancelled(true);}@EventHandler public void bp(BlockPlaceEvent e){if(locked(e.getPlayer()))e.setCancelled(true);}private boolean locked(Player p){return !bypass(p)&&!logged.contains(p.getUniqueId());}private boolean bypass(Player p){for(String n:getConfig().getStringList("settings.bypass"))if(n.equalsIgnoreCase(p.getName()))return true;return false;}private String hash(String in){try{MessageDigest md=MessageDigest.getInstance("SHA-256");byte[] b=md.digest(in.getBytes());StringBuilder sb=new StringBuilder();for(byte x:b)sb.append(String.format("%02x",x));return sb.toString();}catch(Exception e){return in;}}private void save(){try{data.save(f);}catch(Exception e){e.printStackTrace();}}private String msg(String k){return color(getConfig().getString("messages.prefix","")+getConfig().getString("messages."+k,""));}private String color(String t){return ChatColor.translateAlternateColorCodes('&',t==null?"":t);}}
